import React, { createContext, useContext, useState, ReactNode } from 'react';
import { colors as defaultColors, radii as defaultRadii, shadows as defaultShadows, font as defaultFont } from './tokens';

export interface DesignSystem {
  colors: typeof defaultColors;
  radii: typeof defaultRadii;
  shadows: typeof defaultShadows;
  font: typeof defaultFont;
}

const defaultDesignSystem: DesignSystem = {
  colors: defaultColors,
  radii: defaultRadii,
  shadows: defaultShadows,
  font: defaultFont,
};

const DesignSystemContext = createContext<{
  designSystem: DesignSystem;
  setDesignSystem: (ds: DesignSystem) => void;
}>({
  designSystem: defaultDesignSystem,
  setDesignSystem: () => {},
});

export const useDesignSystem = () => useContext(DesignSystemContext);

export const DesignSystemProvider = ({ children }: { children: ReactNode }) => {
  const [designSystem, setDesignSystem] = useState<DesignSystem>(defaultDesignSystem);
  return (
    <DesignSystemContext.Provider value={{ designSystem, setDesignSystem }}>
      {children}
    </DesignSystemContext.Provider>
  );
};
